.darma-loader-darma-custom-101 {
  width: 40px;
  aspect-ratio: 1;
  display: flex;
}
.darma-loader-darma-custom-101:before,
.darma-loader-darma-custom-101:after {
  content: "";
  flex: 1;
  background: var(--loader-color, #f03355);
  animation: darma-loader-darma-custom-101-l21 2s infinite;
  border-radius: 100px 0 0 100px;
  transform-origin: top right;
  transform: translateY(calc(var(--s,1)*0%)) rotate(0);
}
.darma-loader-darma-custom-101:after {
  transform-origin: bottom left;
  border-radius: 0 100px 100px 0;
  --s:-1;
}
@keyframes darma-loader-darma-custom-101-l21 {
  33%  {transform: translate(0,calc(var(--s,1)*50%)) rotate(0)}
  66%  {transform: translate(0,calc(var(--s,1)*50%)) rotate(-90deg)}
  90%,
  100% {transform: translate(calc(var(--s,1)*-100%),calc(var(--s,1)*50%))  rotate(-90deg)}
}

